      env: {
        JAM_AGENT_ID: agentName,
        JAM_ELEMENT_IDS: files.filter(file => file.startsWith('public/elements/')).join(',')
      }
    });
  }

  console.log(`[promote] promoted ${files.length} file(s) from ${candidate}`);
}

